### S3 Uploads (Production)

```typescript
// common/services/s3-upload.service.ts
import { Injectable } from '@nestjs/common';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { ConfigService } from '@nestjs/config';
import { v4 as uuidv4 } from 'uuid';

@Injectable()
export class S3UploadService {
  private s3: S3Client;
  private bucket: string;

  constructor(private config: ConfigService) {
    this.s3 = new S3Client({
      region: config.get('AWS_REGION'),
      credentials: {
        accessKeyId: config.get('AWS_ACCESS_KEY_ID'),
        secretAccessKey: config.get('AWS_SECRET_ACCESS_KEY'),
      },
    });
    this.bucket = config.get('S3_BUCKET');
  }

  async upload(file: Express.Multer.File, folder: string): Promise<string> {
    const key = `${folder}/${uuidv4()}-${file.originalname}`;

    await this.s3.send(
      new PutObjectCommand({
        Bucket: this.bucket,
        Key: key,
        Body: file.buffer,
        ContentType: file.mimetype,
      }),
    );

    return `https://${this.bucket}.s3.amazonaws.com/${key}`;
  }
}
```

## Advanced Filtering

```typescript
// posts/dto/filter-posts.dto.ts
export class FilterPostsDto extends PaginationQueryDto {
  @IsOptional()
  @IsString()
  search?: string;

  @IsOptional()
  @IsString()
  authorId?: string;

  @IsOptional()
  @Transform(({ value }) => value === 'true')
  @IsBoolean()
  published?: boolean;

  @IsOptional()
  @Transform(({ value }) =>
    typeof value === 'string' ? value.split(',') : value,
  )
  @IsArray()
  @IsString({ each: true })
  tags?: string[];

  @IsOptional()
  @Type(() => Date)
  @IsDate()
  startDate?: Date;

  @IsOptional()
  @Type(() => Date)
  @IsDate()
  endDate?: Date;

  @IsOptional()
  @IsEnum(['title', 'createdAt', 'updatedAt'])
  sortBy?: string = 'createdAt';
}
```

```typescript
// posts/posts.service.ts
async findAll(query: FilterPostsDto) {
  const where: Prisma.PostWhereInput = {
    AND: [
      query.published !== undefined ? { published: query.published } : {},
      query.authorId ? { authorId: query.authorId } : {},
      query.search
        ? {
            OR: [
              { title: { contains: query.search, mode: 'insensitive' } },
              { content: { contains: query.search, mode: 'insensitive' } },
              { author: { name: { contains: query.search, mode: 'insensitive' } } },
            ],
          }
        : {},
      query.tags?.length
        ? { tags: { some: { name: { in: query.tags } } } }
        : {},
      query.startDate || query.endDate
        ? {
            createdAt: {
              ...(query.startDate && { gte: query.startDate }),
              ...(query.endDate && { lte: query.endDate }),
            },
          }
        : {},
    ],
  };

  const [data, total] = await Promise.all([
    this.prisma.post.findMany({
      where,
      skip: (query.page - 1) * query.limit,
      take: query.limit,
      orderBy: { [query.sortBy]: query.sortOrder },
      include: {
        author: { select: { id: true, name: true, avatar: true } },
        tags: { select: { id: true, name: true } },
        _count: { select: { comments: true } },
      },
    }),
    this.prisma.post.count({ where }),
  ]);

  return {
    data,
    meta: {
      total,
      page: query.page,
      limit: query.limit,
      totalPages: Math.ceil(total / query.limit),
    },
  };
}
```

